/// <summary>
/// This class is an extension of <c>PurchTableForm</c>
/// </summary>
[ExtensionOf(classstr(PurchTableForm))]
internal final class ETGPurchTableForm_Extension
{
}

Method.Source:
/// <summary>
/// Setting the CapexApprovalId field mandatory.
/// </summary>
/// <param name = "_purchTable">PurchTable</param>
/// <param name = "_purchLine">PurchLine</param>
/// <param name = "_purchLine_ds">FormDataSource</param>
public void setAllowEditAssetFields (PurchTable _purchTable, PurchLine _purchLine, FormDataSource _purchLine_ds)
{
    next setAllowEditAssetFields(_purchTable, _purchLine, _purchLine_ds);
    if (AssetParameters::find().ETGCapexApprovalIdFeature == NoYes::Yes)
    {
        _purchLine_ds.object(fieldNum(PurchLine, ETGCapexApprovalId)).mandatory(_purchLine.CreateFixedAsset == NoYes::Yes);
    }
}
